const body = $json.body || $json;
const now = new Date().toISOString();

return [{
  json: {
    request_id: body.request_id || `INC-${Date.now()}`,
    received_at: now,
    source: body.source || 'webhook',
    business_unit: body.business_unit || 'Unknown',
    summary: body.summary || '',
    description: body.description || '',
    affected_users: Number(body.affected_users || 1),
    system: body.system || 'Unknown',
    urgency: String(body.urgency || 'medium').toLowerCase(),
    raw_text: `${body.summary || ''} ${body.description || ''} ${body.system || ''}`.toLowerCase()
  }
}];

const incident = $json;
const kb = [
  {
    id: 'KB-SAP-ACCESS-001',
    title: 'SAP role assignment and tile access issues',
    category: 'Access Management',
    keywords: ['sap', 's/4hana', 'role', 'roles', 'fiori', 'tile', 'invoice', 'approval', 'access'],
    guidance: 'Check recent role assignment changes, Fiori catalog mapping, and identity sync status. For more than five affected users, route to identity/access support and request approval before changing roles.'
  },
  {
    id: 'KB-CI-PIPELINE-002',
    title: 'CI pipeline failure after dependency update',
    category: 'Developer Productivity',
    keywords: ['ci', 'pipeline', 'github', 'actions', 'dependency', 'package', 'build', 'release'],
    guidance: 'Compare lockfile changes, inspect failing job logs, run dependency rollback test, and create a developer ticket with the failing workflow URL.'
  },
  {
    id: 'KB-DASHBOARD-ACCESS-003',
    title: 'Read-only analytics dashboard access',
    category: 'Access Management',
    keywords: ['dashboard', 'power bi', 'reporting', 'read-only', 'sales', 'customer'],
    guidance: 'Verify manager approval and assign the user to the read-only reporting group. Single-user low-risk requests can be prepared automatically but still require approval.'
  },
  {
    id: 'KB-SECURITY-004',
    title: 'Suspicious login or credential risk',
    category: 'Security',
    keywords: ['phishing', 'credential', 'suspicious', 'login', 'mfa', 'breach', 'password'],
    guidance: 'Escalate immediately to security operations. Do not auto-resolve. Preserve logs, lock risky sessions, and require human review.'
  }
];

const scored = kb.map(entry => {
  const score = entry.keywords.reduce((sum, keyword) => sum + (incident.raw_text.includes(keyword) ? 1 : 0), 0);
  return { ...entry, score };
}).sort((a, b) => b.score - a.score);

const match = scored[0].score > 0 ? scored[0] : {
  id: 'KB-GENERAL-000',
  title: 'General support triage',
  category: 'General IT',
  score: 0,
  guidance: 'Create a support ticket, collect logs or screenshots, and route to the responsible application owner.'
};

return [{ json: { ...incident, knowledge_match: match } }];

const item = $json;
const text = item.raw_text;
const affected = item.affected_users;
const urgency = item.urgency;
const category = item.knowledge_match.category;

const securitySignals = ['phishing', 'credential', 'breach', 'suspicious', 'mfa', 'password'].some(term => text.includes(term));
const outageSignals = ['outage', 'down', 'unavailable', 'cannot open', 'failed for all'].some(term => text.includes(term));
const accessChange = category === 'Access Management' || ['access', 'role', 'permission'].some(term => text.includes(term));

let severity = 'P4';
if (securitySignals || affected > 50 || outageSignals && affected > 20) severity = 'P1';
else if (urgency === 'high' || affected > 10) severity = 'P2';
else if (urgency === 'medium' || affected > 1) severity = 'P3';

let risk = 'low';
if (securitySignals || severity === 'P1') risk = 'high';
else if (accessChange || severity === 'P2') risk = 'medium';

const humanApprovalRequired = risk !== 'low' || accessChange || affected > 5;
const recommendedAction = humanApprovalRequired
  ? 'Create ticket and route to the responsible owner before executing changes.'
  : 'Prepare automated response and keep the case available for service-desk review.';

return [{
  json: {
    request_id: item.request_id,
    received_at: item.received_at,
    source: item.source,
    business_unit: item.business_unit,
    system: item.system,
    summary: item.summary,
    category,
    severity,
    risk,
    confidence: item.knowledge_match.score >= 3 ? 'high' : item.knowledge_match.score > 0 ? 'medium' : 'low',
    human_approval_required: humanApprovalRequired,
    recommended_action: recommendedAction,
    knowledge_match: {
      id: item.knowledge_match.id,
      title: item.knowledge_match.title,
      guidance: item.knowledge_match.guidance
    },
    next_steps: [
      item.knowledge_match.guidance,
      humanApprovalRequired ? 'Request human approval before taking action.' : 'Send prepared response and monitor for reopen events.',
      'Store the decision record for later audit and workflow evaluation.'
    ],
    audit: {
      workflow: 'enterprise-incident-triage',
      decision_version: '2026.05',
      automation_mode: humanApprovalRequired ? 'assistive' : 'supervised-auto',
      rule_basis: ['urgency', 'affected_users', 'category', 'risk_signals'],
      generated_at: new Date().toISOString()
    }
  }
}];

return [{
  json: {
    ...$json,
    queue: 'human-review',
    ticket_stub: {
      title: `[${$json.severity}] ${$json.summary}`,
      assignment_group: $json.category === 'Security' ? 'Security Operations' : $json.category,
      approval_reason: `${$json.risk} risk / ${$json.affected_users || 'unknown'} affected user(s)`
    }
  }
}];
